import type { MovementPattern, TrainingType } from "./metadata";
import type {
  Equipment,
  EquipmentSubtype,
  PrimaryBucket,
  MuscleGroupCoarse,
  MuscleGroupDetailed,
} from "./taxonomy";

/** Lifecycle for bundled preload rows; UI filtering is deferred until consumers opt in. */
export type ExerciseDefinitionStatus = "active" | "archived" | "retired";

export type ExerciseLibraryItemV1 = {
  exerciseId: string;
  name: string;
  aliases: string[];
  equipment: Equipment;
  /** Optional refinement for Machine/CardioMachine; used for gym-aware availability. */
  equipmentSubtype?: EquipmentSubtype;
  primaryBucket: PrimaryBucket;
  movement: MovementPattern;
  trainingType: TrainingType;
  primaryCoarse: MuscleGroupCoarse[];
  secondaryCoarse: MuscleGroupCoarse[];
  primaryDetailed: MuscleGroupDetailed[];
  secondaryDetailed: MuscleGroupDetailed[];
  cues?: string[];
  description?: string;
  status: ExerciseDefinitionStatus;
  /** When `status` is `retired`, analytics may follow this bundled catalog id (optional). */
  successorExerciseId?: string;
};

function assertSnakeCase(id: string): void {
  if (!/^[a-z0-9]+(_[a-z0-9]+)*$/.test(id)) {
    throw new Error(`exerciseId must be snake_case: ${id}`);
  }
}

function item(x: ExerciseLibraryItemV1): ExerciseLibraryItemV1 {
  assertSnakeCase(x.exerciseId);
  return x;
}

function make(x: Omit<ExerciseLibraryItemV1, "status"> & { status?: ExerciseDefinitionStatus }): ExerciseLibraryItemV1 {
  return item({ ...x, status: x.status ?? "active" });
}

